class Solution:
    def minOperations(self, nums, k, queries):
        ans = []
        for l, r in queries:
            rems = [nums[i] % k for i in range(l, r + 1)]
            if len(set(rems)) != 1:
                ans.append(-1)
                continue
            quots = sorted(nums[i] // k for i in range(l, r + 1))
            med = quots[len(quots) // 2]
            ans.append(sum(abs(q - med) for q in quots))
        return ans

