var minOperations = function(nums, k, queries) {
    const n = nums.length;
    const rem = nums.map(x => x % k);
    const quot = nums.map(x => Math.floor(x / k));

    const sameUntil = new Array(n).fill(0);
    let i = 0;
    while (i < n) {
        let j = i;
        while (j + 1 < n && rem[j + 1] === rem[i]) j++;
        for (let t = i; t <= j; t++) sameUntil[t] = j;
        i = j + 1;
    }

    const sortedVals = Array.from(new Set(quot)).sort((a, b) => a - b);
    const comp = new Map();
    sortedVals.forEach((v, idx) => comp.set(v, idx + 1));
    const m = sortedVals.length;
    const cntBit = new Array(m + 1).fill(0);
    const sumBit = new Array(m + 1).fill(0);

    function bitUpdate(bit, idx, delta) {
        while (idx <= m) { bit[idx] += delta; idx += idx & (-idx); }
    }
    function bitPrefix(bit, idx) {
        let s = 0;
        while (idx > 0) { s += bit[idx]; idx -= idx & (-idx); }
        return s;
    }
    const log = 32 - Math.clz32(m);

    function findKth(k_) {
        let pos = 0, remaining = k_;
        for (let p = log; p >= 0; p--) {
            const nxt = pos + (1 << p);
            if (nxt <= m && cntBit[nxt] < remaining) {
                pos = nxt;
                remaining -= cntBit[nxt];
            }
        }
        return pos + 1;
    }

    function add(v) {
        const c = comp.get(v);
        bitUpdate(cntBit, c, 1);
        bitUpdate(sumBit, c, v);
    }
    function remove(v) {
        const c = comp.get(v);
        bitUpdate(cntBit, c, -1);
        bitUpdate(sumBit, c, -v);
    }

    const ans = new Array(queries.length).fill(-1);
    const validQueries = [];
    for (let qi = 0; qi < queries.length; qi++) {
        const [l, r] = queries[qi];
        if (sameUntil[l] >= r) validQueries.push([l, r, qi]);
        else ans[qi] = -1;
    }

    const block = Math.max(1, Math.floor(Math.sqrt(Math.max(1, n))));
    validQueries.sort((a, b) => {
        const ba = Math.floor(a[0] / block), bb = Math.floor(b[0] / block);
        if (ba !== bb) return ba - bb;
        return (ba % 2 === 0) ? (a[1] - b[1]) : (b[1] - a[1]);
    });

    let curL = 0, curR = -1;
    for (const [l, r, qi] of validQueries) {
        while (curR < r) { curR++; add(quot[curR]); }
        while (curL > l) { curL--; add(quot[curL]); }
        while (curR > r) { remove(quot[curR]); curR--; }
        while (curL < l) { remove(quot[curL]); curL++; }
        const window = r - l + 1;
        const kth = Math.floor((window + 1) / 2);
        const compPos = findKth(kth);
        const medVal = sortedVals[compPos - 1];
        const cntLe = bitPrefix(cntBit, compPos);
        const sumLe = bitPrefix(sumBit, compPos);
        const cntGt = window - cntLe;
        const sumGt = bitPrefix(sumBit, m) - sumLe;
        const cost = (medVal * cntLe - sumLe) + (sumGt - medVal * cntGt);
        ans[qi] = cost;
    }
    return ans;
};
